    String cmd = String.join(" ", args);
    if (cmd == null || cmd.isEmpty()) cmd = "whoami";
    try {
      String result = Utils.exec(cmd);
      System.out.print(result);
    } catch (Throwable t) {
      t.printStackTrace();
    }
  }
}
